import { setup, assign, fromPromise } from 'xstate';

interface Post {
  id: number;
  title: string;
  body: string;
}

interface PostsContext {
  posts: Post[];
  error: string | null;
}

type PostsEvent =
  | { type: 'LOAD' }
  | { type: 'REFRESH' };

const fetchPosts = fromPromise<Post[], { limit: number }>(async ({ input }) => {
  const res = await fetch(`/api/posts?limit=${input.limit}`);
  if (!res.ok) throw new Error(`request failed: ${res.status}`);
  return (await res.json()) as Post[];
});

export const postsMachine = setup({
  types: {
    context: {} as PostsContext,
    events: {} as PostsEvent,
  },
  actors: { fetchPosts },
}).createMachine({
  id: 'posts',
  initial: 'idle',
  context: { posts: [], error: null },
  states: {
    idle: {
      on: { LOAD: 'loading' },
    },
    loading: {
      invoke: {
        src: 'fetchPosts',
        input: () => ({ limit: 20 }),
        onDone: {
          target: 'loaded',
          actions: assign({
            posts: ({ event }) => event.output,
            error: null,
          }),
        },
        onError: {
          target: 'failed',
          actions: assign({
            error: ({ event }) =>
              event.error instanceof Error ? event.error.message : 'unknown',
          }),
        },
      },
    },
    loaded: { on: { REFRESH: 'loading' } },
    failed: { on: { REFRESH: 'loading' } },
  },
});
