import { setup, assign, fromPromise } from 'xstate';

type ReportParams = {
  from: string;
  to: string;
  format: 'csv' | 'pdf';
};

type ReportResult = { url: string; size: number };

type Ctx = {
  params: ReportParams;
  result: ReportResult | null;
  error: string | null;
};

type Ev =
  | { type: 'GENERATE'; params: ReportParams }
  | { type: 'RESET' };

const generateReport = fromPromise<ReportResult, ReportParams>(
  async ({ input }) => {
    const res = await fetch('/api/reports', {
      method: 'POST',
      body: JSON.stringify(input),
      headers: { 'content-type': 'application/json' },
    });
    if (!res.ok) throw new Error(`report failed: ${res.status}`);
    return (await res.json()) as ReportResult;
  }
);

export const reportMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { generateReport },
}).createMachine({
  id: 'report',
  initial: 'idle',
  context: {
    params: { from: '', to: '', format: 'csv' },
    result: null,
    error: null,
  },
  states: {
    idle: {
      on: {
        GENERATE: {
          target: 'working',
          actions: assign({ params: ({ event }) => event.params }),
        },
      },
    },
    working: {
      invoke: {
        src: 'generateReport',
        input: ({ context }) => context.params,
        onDone: {
          target: 'done',
          actions: assign({ result: ({ event }) => event.output }),
        },
        onError: {
          target: 'failed',
          actions: assign({ error: ({ event }) => String(event.error) }),
        },
      },
    },
    done: { on: { RESET: 'idle' } },
    failed: { on: { RESET: 'idle' } },
  },
});
