Refactor this v5 machine to declare the fromPromise actor and validation guard in setup (referenced by string):

```ts
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { url: string; body: string | null; err: string | null };
type Ev = { type: 'FETCH'; url: string };

export const m = setup({
  types: { context: {} as Ctx, events: {} as Ev },
}).createMachine({
  initial: 'idle',
  context: { url: '', body: null, err: null },
  states: {
    idle: {
      on: {
        FETCH: {
          guard: ({ event }) => event.url.startsWith('https://'),
          target: 'loading',
          actions: assign({ url: ({ event }) => event.url }),
        },
      },
    },
    loading: {
      invoke: {
        src: fromPromise<string, { url: string }>(async ({ input }) => {
          const r = await fetch(input.url);
          return r.text();
        }),
        input: ({ context }) => ({ url: context.url }),
        onDone: {
          target: 'done',
          actions: assign({ body: ({ event }) => event.output }),
        },
        onError: {
          target: 'idle',
          actions: assign({ err: ({ event }) => String(event.error) }),
        },
      },
    },
    done: {},
  },
});
