import { setup, assign, fromPromise } from 'xstate';

interface Page<T> {
  items: T[];
  nextCursor: string | null;
}

interface Article {
  slug: string;
  title: string;
}

interface Ctx {
  cursor: string | null;
  articles: Article[];
  error: string | null;
}

type Ev =
  | { type: 'LOAD' }
  | { type: 'NEXT' };

const loadPage = fromPromise<Page<Article>, { cursor: string | null }>(
  async ({ input }) => {
    const qs = input.cursor ? `?cursor=${input.cursor}` : '';
    const res = await fetch(`/api/articles${qs}`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return (await res.json()) as Page<Article>;
  }
);

export const articlesMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { loadPage },
}).createMachine({
  id: 'articles',
  initial: 'idle',
  context: { cursor: null, articles: [], error: null },
  states: {
    idle: { on: { LOAD: 'loading' } },
    loading: {
      invoke: {
        src: 'loadPage',
        input: ({ context }) => ({ cursor: context.cursor }),
        onDone: {
          target: 'loaded',
          actions: assign({
            articles: ({ context, event }) => [
              ...context.articles,
              ...event.output.items,
            ],
            cursor: ({ event }) => event.output.nextCursor,
          }),
        },
        onError: {
          target: 'failed',
          actions: assign({ error: ({ event }) => String(event.error) }),
        },
      },
    },
    loaded: { on: { NEXT: 'loading' } },
    failed: {},
  },
});
