import { setup, assign, fromPromise } from 'xstate';

type Credentials = { email: string; password: string };
type Session = { token: string; expiresAt: number };

type Ctx = {
  creds: Credentials;
  session: Session | null;
  error: string | null;
};

type Ev =
  | { type: 'SUBMIT'; creds: Credentials }
  | { type: 'LOGOUT' }
  | { type: 'RETRY' };

const authenticate = fromPromise<Session, Credentials>(async ({ input }) => {
  const res = await fetch('/api/auth/login', {
    method: 'POST',
    body: JSON.stringify(input),
    headers: { 'content-type': 'application/json' },
  });
  if (!res.ok) throw new Error('invalid credentials');
  return (await res.json()) as Session;
});

export const authMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { authenticate },
}).createMachine({
  id: 'auth',
  initial: 'anonymous',
  context: {
    creds: { email: '', password: '' },
    session: null,
    error: null,
  },
  states: {
    anonymous: {
      on: {
        SUBMIT: {
          target: 'authenticating',
          actions: assign({ creds: ({ event }) => event.creds }),
        },
      },
    },
    authenticating: {
      invoke: {
        src: 'authenticate',
        input: ({ context }) => context.creds,
        onDone: {
          target: 'authenticated',
          actions: assign({
            session: ({ event }) => event.output,
            error: null,
          }),
        },
        onError: {
          target: 'rejected',
          actions: assign({ error: ({ event }) => String(event.error) }),
        },
      },
    },
    authenticated: {
      on: { LOGOUT: 'anonymous' },
    },
    rejected: {
      on: { RETRY: 'authenticating', LOGOUT: 'anonymous' },
    },
  },
});
