import { setup, assign, fromPromise } from 'xstate';

type Draft = { id: string; body: string };

type Ctx = {
  draft: Draft;
  saved: boolean;
  error: string | null;
};

type Ev =
  | { type: 'EDIT'; body: string }
  | { type: 'SAVE' };

export const draftMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    saveDraft: fromPromise<Draft, { draft: Draft }>(async ({ input }) => {
      const res = await fetch(`/api/drafts/${input.draft.id}`, {
        method: 'PUT',
        body: JSON.stringify(input.draft),
        headers: { 'content-type': 'application/json' },
      });
      if (!res.ok) throw new Error(`save failed ${res.status}`);
      return (await res.json()) as Draft;
    }),
  },
}).createMachine({
  id: 'draft',
  initial: 'editing',
  context: {
    draft: { id: 'd1', body: '' },
    saved: false,
    error: null,
  },
  states: {
    editing: {
      on: {
        EDIT: {
          actions: assign({
            draft: ({ context, event }) => ({
              ...context.draft,
              body: event.body,
            }),
            saved: false,
          }),
        },
