In XState v5, register a `fromPromise(...)` actor in `setup.actors` and reference it by name from `invoke.src`. When the promise resolves, `onDone` fires with typed `event.output`. When it rejects, `onError` fires with `event.error`. Both transitions can carry `assign` actions that capture the result into context.

```ts
import { setup, assign, fromPromise } from 'xstate';

type Stats = { totalUsers: number; activeUsers: number };

type Ctx = {
  stats: Stats | null;
  error: string | null;
};

type Ev = { type: 'REFRESH' };

export const dashboardMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    fetchStats: fromPromise<Stats, void>(async () => {
      const res = await fetch('/api/stats');
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      return (await res.json()) as Stats;
    }),
  },
}).createMachine({
  id: 'dashboard',
  initial: 'idle',
  context: { stats: null, error: null },
  states: {
    idle: { on: { REFRESH: 'loading' } },
    loading: {
      invoke: {
        src: 'fetchStats',
        onDone: {
          target: 'idle',
          actions: assign({
            stats: ({ event }) => event.output,
            error: null,
          }),
        },
        onError: {
          target: 'idle',
          actions: assign({
            error: ({ event }) => String(event.error),
          }),
        },
      },
    },
  },
});
```

