import { setup, assign } from 'xstate';

interface AttemptInput {
  attempt: number;
}

interface AttemptOutput {
  succeeded: boolean;
  attempt: number;
}

const attemptMachine = setup({
  types: {
    input: {} as AttemptInput,
    context: {} as { attempt: number; succeeded: boolean },
    events: {} as
      | { type: 'SUCCESS' }
      | { type: 'FAILURE' },
    output: {} as AttemptOutput,
  },
}).createMachine({
  id: 'attempt',
  initial: 'working',
  context: ({ input }) => ({ attempt: input.attempt, succeeded: false }),
  states: {
    working: {
      on: {
        SUCCESS: {
          target: 'done',
          actions: assign({ succeeded: true }),
        },
        FAILURE: {
          target: 'done',
          actions: assign({ succeeded: false }),
        },
      },
    },
    done: { type: 'final' },
  },
  output: ({ context }) => ({
    succeeded: context.succeeded,
    attempt: context.attempt,
  }),
});

interface ParentCtx {
  attempts: number;
  lastResult: boolean | null;
}

type ParentEv = { type: 'RUN' };

export const retryMachine = setup({
  types: { context: {} as ParentCtx, events: {} as ParentEv },
  actors: { attemptMachine },
  guards: {
    shouldStop: ({ context }) =>
      context.lastResult === true || context.attempts >= 3,
  },
}).createMachine({
  id: 'retry',
  initial: 'idle',
  context: { attempts: 0, lastResult: null },
  states: {
    idle: {
      on: { RUN: 'trying' },
    },
    trying: {
      invoke: {
        src: 'attemptMachine',
        input: ({ context }) => ({ attempt: context.attempts + 1 }),
        onDone: [
          {
            guard: 'shouldStop',
            target: 'idle',
            actions: assign({
              lastResult: ({ event }) => event.output.succeeded,
              attempts: ({ event }) => event.output.attempt,
            }),
          },
          {
            target: 'trying',
            reenter: true,
            actions: assign({
              lastResult: ({ event }) => event.output.succeeded,
              attempts: ({ event }) => event.output.attempt,
            }),
          },
        ],
      },
    },
  },
});
